using Api.Constants;
using Application.DTOs.Chat;
using Application.Features.App.Chat.Conversations.Commands.CreateGroupConversation;
using Application.Option;
using Application.Services.Interface;
using Microsoft.Extensions.Options;

namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for creating a new group chat conversation.
/// </summary>
public class CreateGroupEndPoint : ICarterModule
{
    /// <summary>
    /// Configures the route for group conversation creation.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/groups", async (
            HttpContext context,
            [FromForm] string name,
            ISender sender,
            IUploadServiceApi uploadServiceApi,
            IOptions<PathOption> options,
            CancellationToken cancellationToken) =>
        {
            try
            {
                var form = await context.Request.ReadFormAsync(cancellationToken);
                var memberUserIds = ParseMemberUserIds(form);
                string? avatarUrl = null;

                var avatar = form.Files.GetFile("avatar");
                if (avatar is { Length: > 0 })
                {
                    var uploaded = await uploadServiceApi.UploadAsync(
                        options.Value.ChatFiles,
                        [avatar]);
                    avatarUrl = uploaded.FirstOrDefault()?.Name;
                }

                var res = await sender.Send(
                    new CreateGroupConversationCommand(name, avatarUrl, memberUserIds),
                    cancellationToken);

                if (res.IsSuccess)
                    return Results.Json(res.Value, statusCode: StatusCodes.Status201Created);
                return Results.Problem(res!.Error!.Description, statusCode: 400);
            }
            catch (Exception ex)
            {
                Log.Error(ex, "CreateGroupConversation");
                return Results.Problem("خطا در ایجاد گروه", statusCode: 400);
            }
        })
        .WithName("CreateGroupConversation")
        .WithTags("Chat")
        .Produces<ConversationDetailDto>(StatusCodes.Status201Created)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Create group conversation")
