using Microsoft.AspNetCore.Http;

namespace Application.Features.App.Chat.Messages.Commands.SendChatMessage;

public record SendChatMessageCommand(
    int ConversationId,
    string? Text,
    int? ReplyToMessageId,
    List<IFormFile> Attachments) : IRequest<Result<ChatMessageDto>>;

public class SendChatMessageCommandValidator : AbstractValidator<SendChatMessageCommand>
{
    public SendChatMessageCommandValidator()
    {
        RuleFor(x => x.ConversationId)
            .GreaterThan(0).WithMessage("شناسه مکالمه نامعتبر است");

        RuleFor(x => x.Text)
            .MaximumLength(4000).WithMessage("متن پیام نباید بیشتر از ۴۰۰۰ کاراکتر باشد");

        RuleFor(x => x)
            .Must(x => !string.IsNullOrWhiteSpace(x.Text) || x.Attachments.Count > 0)
            .WithMessage("پیام نمی‌تواند خالی باشد")
            .WithName("Message");

        RuleForEach(x => x.Attachments)
            .Must(f => f.Length <= 52_428_800)
            .WithMessage("حجم فایل بیش از ۵۰ مگابایت مجاز نیست");
    }
}

using Application.DTOs.Chat;
using Application.Option;
using Application.Services.Interface;
using Microsoft.Extensions.Options;

namespace Application.Features.App.Chat.Messages.Commands.SendChatMessage;

public class SendChatMessageCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IUploadServiceApi uploadServiceApi,
    IOptions<PathOption> pathOption)
    : IRequestHandler<SendChatMessageCommand, Result<ChatMessageDto>>
{
    public async Task<Result<ChatMessageDto>> Handle(
        SendChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var participant = await context.ChatParticipants
                .AsNoTracking()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (participant is null)
                return ChatErrors.NotAParticipant;

            var conversationType = await context.ChatConversations
                .AsNoTracking()
                .Where(cv => cv.Id == request.ConversationId)
                .Select(cv => cv.Type)
                .FirstOrDefaultAsync(cancellationToken);

            if (conversationType == ChatConversationType.Channel
                && participant.Role != ChatParticipantRole.Admin)
                return ChatErrors.ChannelMembersCannotSend;

            int? validatedReplyToId = request.ReplyToMessageId;
            if (validatedReplyToId.HasValue)
            {
                var replyExists = await context.ChatMessages
                    .AsNoTracking()
                    .AnyAsync(m =>
                        m.Id == validatedReplyToId.Value
                        && m.ConversationId == request.ConversationId,
                        cancellationToken);

                if (!replyExists)
                    validatedReplyToId = null;
            }

            var message = new ChatMessage
            {
                ConversationId = request.ConversationId,
                SenderId = currentUserId,
                Text = string.IsNullOrWhiteSpace(request.Text) ? null : request.Text.Trim(),
                ReplyToMessageId = validatedReplyToId
            };

            if (request.Attachments.Count > 0)
            {
                var fileResults = await uploadServiceApi.UploadAsync(
                    pathOption.Value.ChatFiles,
                    request.Attachments);

                for (var i = 0; i < request.Attachments.Count; i++)
                {
                    var file = request.Attachments[i];
                    var uploaded = fileResults[i];

                    message.Attachments.Add(new ChatMessageAttachment
                    {
                        FileUrl = uploaded.Name,
                        FileName = file.FileName,
                        FileSize = file.Length,
                        ContentType = string.IsNullOrWhiteSpace(file.ContentType)
                            ? "application/octet-stream"
                            : file.ContentType
                    });
                }
            }

            context.ChatMessages.Add(message);
            await context.SaveChangesAsync(cancellationToken);

            var sender = await context.AppUsers
                .AsNoTracking()
                .Where(u => u.Id == currentUserId)
                .Select(u => new { u.Name, u.ProfileImage })
                .FirstOrDefaultAsync(cancellationToken);

            ChatMessageReplySnapshotDto? replySnapshot = null;
            if (message.ReplyToMessageId.HasValue)
            {
                var original = await context.ChatMessages
                    .AsNoTracking()
                    .Where(m => m.Id == message.ReplyToMessageId.Value)
                    .Select(m => new
                    {
                        m.Id,
                        SenderName = m.Sender.Name,
                        m.Text,
                        m.IsDeleted
                    })
                    .FirstOrDefaultAsync(cancellationToken);

                if (original is not null)
                {
                    replySnapshot = new ChatMessageReplySnapshotDto
                    {
                        MessageId = original.Id,
                        SenderName = original.SenderName,
                        TextPreview = original.IsDeleted ? null : TruncatePreview(original.Text),
                        IsDeleted = original.IsDeleted
                    };
                }
            }

            var dto = new ChatMessageDto
            {
                Id = message.Id,
                ConversationId = message.ConversationId,
                SenderId = currentUserId,
                SenderName = sender?.Name ?? string.Empty,
                SenderAvatarUrl = string.IsNullOrEmpty(sender?.ProfileImage) ? null : sender.ProfileImage,
                Text = message.Text,
                IsDeleted = false,
                IsEdited = false,
                SentAt = message.CreateDate,
                ReplyTo = replySnapshot,
                ForwardedFrom = null,
                Attachments = message.Attachments.Select(a => new ChatFileDto
                {
                    Id = a.Id,
                    FileName = a.FileName,
                    FileUrl = a.FileUrl,
                    FileSize = a.FileSize,
                    ContentType = a.ContentType
                }).ToList()
            };

            // TODO Day 6: await _chatNotificationService.SendMessageAsync(...)

            return Result<ChatMessageDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (SendChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static string? TruncatePreview(string? text)
    {
        if (string.IsNullOrEmpty(text))
            return null;

        return text.Length <= 100 ? text : text[..100];
    }
}

using Application.DTOs.Chat;

namespace Application.Features.App.Chat.Messages.Queries.GetChatMessages;

public record GetChatMessagesQuery(
    int ConversationId,
    int? BeforeMessageId = null,
    int PageSize = 20,
    string? Search = null) : IRequest<Result<ChatMessagePageDto>>;

using Application.DTOs.Chat;

namespace Application.Features.App.Chat.Messages.Queries.GetChatMessages;

public class GetChatMessagesQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetChatMessagesQuery, Result<ChatMessagePageDto>>
{
    public async Task<Result<ChatMessagePageDto>> Handle(
        GetChatMessagesQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var isMember = await context.ChatParticipants
                .AsNoTracking()
                .AnyAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (!isMember)
                return ChatErrors.NotAParticipant;

            var pageSize = Math.Min(Math.Max(request.PageSize, 1), 50);

            var qBase = context.ChatMessages
                .AsNoTracking()
                .Where(m => m.ConversationId == request.ConversationId);

            if (request.BeforeMessageId.HasValue)
                qBase = qBase.Where(m => m.Id < request.BeforeMessageId.Value);

            if (!string.IsNullOrWhiteSpace(request.Search))
            {
                var search = request.Search.ToLower();
                qBase = qBase.Where(m =>
                    !m.IsDeleted
                    && m.Text != null
                    && EF.Functions.Like(m.Text.ToLower(), $"%{search}%"));
            }

            var rawMessages = await qBase
                .OrderByDescending(m => m.Id)
                .Take(pageSize + 1)
                .Select(m => new
                {
                    m.Id,
                    m.ConversationId,
                    m.SenderId,
                    SenderName = m.Sender.Name,
                    SenderAvatarUrl = m.Sender.ProfileImage,
                    m.Text,
                    m.IsDeleted,
                    m.IsEdited,
                    m.EditedAt,
                    SentAt = m.CreateDate,
                    m.ReplyToMessageId,
                    ReplyToSenderName = m.ReplyToMessage != null ? m.ReplyToMessage.Sender.Name : null,
                    ReplyToText = m.ReplyToMessage != null ? m.ReplyToMessage.Text : null,
                    ReplyToIsDeleted = m.ReplyToMessage != null && m.ReplyToMessage.IsDeleted,
                    m.ForwardedFromSenderName,
                    m.ForwardedFromSentAt,
                    Attachments = m.Attachments.Select(a => new
                    {
                        a.Id,
                        a.FileName,
                        a.FileUrl,
                        a.FileSize,
                        a.ContentType
                    }).ToList()
                })
                .ToListAsync(cancellationToken);

            var hasMore = rawMessages.Count > pageSize;
            var pageMessages = hasMore
                ? rawMessages.Take(pageSize).ToList()
                : rawMessages;

            var dtos = pageMessages
                .Select(m => new ChatMessageDto
                {
                    Id = m.Id,
                    ConversationId = m.ConversationId,
                    SenderId = m.SenderId,
                    SenderName = m.SenderName,
                    SenderAvatarUrl = string.IsNullOrEmpty(m.SenderAvatarUrl) ? null : m.SenderAvatarUrl,
                    Text = m.IsDeleted ? null : m.Text,
                    IsDeleted = m.IsDeleted,
                    IsEdited = m.IsEdited,
                    SentAt = m.SentAt,
                    EditedAt = m.EditedAt,
                    ReplyTo = m.ReplyToMessageId.HasValue
                        ? new ChatMessageReplySnapshotDto
                        {
                            MessageId = m.ReplyToMessageId.Value,
                            SenderName = m.ReplyToSenderName ?? string.Empty,
                            TextPreview = m.ReplyToIsDeleted ? null : TruncatePreview(m.ReplyToText),
                            IsDeleted = m.ReplyToIsDeleted
                        }
                        : null,
                    ForwardedFrom = !string.IsNullOrEmpty(m.ForwardedFromSenderName)
                        ? new ForwardedFromDto
                        {
                            OriginalSenderName = m.ForwardedFromSenderName,
                            OriginalSentAt = m.ForwardedFromSentAt ?? m.SentAt
                        }
                        : null,
                    Attachments = m.Attachments.Select(a => new ChatFileDto
                    {
                        Id = a.Id,
                        FileName = a.FileName,
                        FileUrl = a.FileUrl,
                        FileSize = a.FileSize,
                        ContentType = a.ContentType
                    }).ToList()
                })
                .OrderBy(m => m.Id)
                .ToList();

            return Result<ChatMessagePageDto>.Success(new ChatMessagePageDto
            {
                Messages = dtos,
                HasMore = hasMore,
                OldestMessageId = dtos.Count > 0 ? dtos[0].Id : null
            });
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (GetChatMessages): {ex.Message}", ex);
            return Error.ServerError;
        }
    }

    private static string? TruncatePreview(string? text)
    {
        if (string.IsNullOrEmpty(text))
            return null;

        return text.Length <= 100 ? text : text[..100];
    }
}

using Api.Constants;
using Application.DTOs.Chat;
using Application.Features.App.Chat.Messages.Commands.SendChatMessage;

namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for sending a message in a chat conversation.
/// </summary>
public class SendChatMessageEndPoint : ICarterModule
{
    /// <summary>
    /// Configures the route for sending chat messages.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/conversations/{conversationId:int}/messages", async (
            HttpContext context,
            int conversationId,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            try
            {
                var form = await context.Request.ReadFormAsync(cancellationToken);

                var text = form.TryGetValue("text", out var textValue)
                    ? textValue.ToString()
                    : null;

                int? replyToMessageId = null;
                if (form.TryGetValue("replyToMessageId", out var replyValue)
                    && int.TryParse(replyValue.ToString(), out var replyId))
                {
                    replyToMessageId = replyId;
                }

                var attachments = form.Files
                    .Where(f => !string.Equals(f.Name, "text", StringComparison.OrdinalIgnoreCase)
                        && !string.Equals(f.Name, "replyToMessageId", StringComparison.OrdinalIgnoreCase))
                    .ToList();

                var command = new SendChatMessageCommand(
                    conversationId,
                    text,
                    replyToMessageId,
                    attachments);

                var res = await sender.Send(command, cancellationToken);

                if (res.IsSuccess)
                    return Results.Json(res.Value, statusCode: StatusCodes.Status201Created);
                return Results.Problem(res!.Error!.Description, statusCode: 400);
            }
            catch (Exception ex)
            {
                Log.Error(ex, "SendChatMessage");
                return Results.Problem("خطا در ارسال پیام", statusCode: 400);
            }
        })
        .WithName("SendChatMessage")
        .WithTags("Chat")
        .Produces<ChatMessageDto>(StatusCodes.Status201Created)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Send chat message")
        .WithDescription("Sends a text message with optional attachments and reply reference in a conversation.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

