            message.IsDeleted = true;
            message.Text = null;
            await context.SaveChangesAsync(cancellationToken);

            await chatNotificationService.MessageDeletedAsync(
                message.ConversationId,
                message.Id,
                cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
