**Full `UploadServiceApi.cs` for context:**

```csharp
using Application.Dto;
using Microsoft.AspNetCore.Http;

namespace Infrastructure.Services;

public class UploadServiceApi : IUploadServiceApi
{
    public async Task<List<FileDto>> UploadAsync(string path, List<IFormFile> files)
    {
        if (!Directory.Exists(path))
        {
            Directory.CreateDirectory(path);
        }
        List<FileDto> allFiles = new List<FileDto>();
        foreach (var file in files)
        {
            if (file.Length > 0)
            {
                string fileName = file.FileName;
                string filePath = Path.Combine(path, fileName);
                int i = 0;
                while (File.Exists(filePath))
                {
                    fileName = $"{i++}_{file.FileName}";
                    filePath = Path.Combine(path, fileName);
                }

                using (var stream = new FileStream(filePath, FileMode.Create))
                {
                    await file.CopyToAsync(stream);
                }
                allFiles.Add(new FileDto(fileName, file.Length, ""));
            }
        }
        return allFiles;
    }
}
```

