## Q3 — `MessagePostEndPoint.cs`

**Complete `AddRoutes` method (verbatim):**

```csharp
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/Message", async (
            HttpContext context
            , [FromForm(Name = "data")] MessageCreateDto request
            , [FromForm(Name = "files")] IList<IFormFile> files
            , ISender sender
            , IUploadServiceApi uploadServiceApi
            , IOptions<PathOption> options) =>
        {
            try
            {
                var form = await context.Request.ReadFormAsync(); // خواندن فرم
                if (request == null)
                {
                    var dataJson = form["data"];
                    var opt = new JsonSerializerOptions { PropertyNamingPolicy = JsonNamingPolicy.CamelCase };
                    request = JsonSerializer.Deserialize<MessageCreateDto>(dataJson!, opt)!;
                }
                if (files == null)
                    files = form.Files.ToList();

                string imagesFolderPath = options.Value.EmailFiles;
                var allFiles = await uploadServiceApi.UploadAsync(imagesFolderPath, files.ToList());

                MessageCreateCommand query = new MessageCreateCommand(request, allFiles);
                var res = await sender.Send(query);

                if (res.IsSuccess)
                    return Results.Ok(res.Value);
                return Results.Problem(res!.Error!.Description, statusCode: 400);
            }
            catch (Exception ex)
            {
                Log.Error(ex, "createMessage");
                return Results.Problem("خطا در آپلود فایل ها", statusCode: 400);

            }

        }).WithName("createMessage")
        .Produces<int>(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("createMessage")
        .WithDescription("createMessage")
            .RequireRateLimiting(RateLimitConst.RateFix)
            .RequireAuthorization()
            .DisableAntiforgery()
            ;
    }
```

**`IFormFile` binding:**

- Parameter: `[FromForm(Name = "files")] IList<IFormFile> files`
- Fallback if `files == null`: `files = form.Files.ToList()` after `ReadFormAsync()`
- Not `IFormFileCollection`; uses `IList<IFormFile>` with `[FromForm]` name `"files"`

