using Application.DTOs.Chat;
using Microsoft.AspNetCore.Http;

namespace Application.Features.App.Chat.Files.Commands.UploadChatFile;

public record UploadChatFileCommand(List<IFormFile> Files) : IRequest<Result<List<ChatFileDto>>>;

using Application.DTOs.Chat;
using Application.Option;
using Application.Services.Interface;
using Microsoft.Extensions.Options;

namespace Application.Features.App.Chat.Files.Commands.UploadChatFile;

public class UploadChatFileCommandHandler(
    IUploadServiceApi uploadServiceApi,
    IOptions<PathOption> pathOption)
    : IRequestHandler<UploadChatFileCommand, Result<List<ChatFileDto>>>
{
    public async Task<Result<List<ChatFileDto>>> Handle(
        UploadChatFileCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            if (request.Files.Count == 0)
                return ChatErrors.EmptyMessage;

            foreach (var file in request.Files)
            {
                if (file.Length > 52_428_800)
                    return ChatErrors.FileTooLarge;
            }

            var uploaded = await uploadServiceApi.UploadAsync(
                pathOption.Value.ChatFiles,
                request.Files);

            var result = new List<ChatFileDto>();
            for (var i = 0; i < uploaded.Count; i++)
            {
                var file = request.Files[i];
                result.Add(new ChatFileDto
                {
                    Id = 0,
                    FileUrl = uploaded[i].Name,
                    FileName = file.FileName,
                    FileSize = file.Length,
                    ContentType = string.IsNullOrWhiteSpace(file.ContentType)
                        ? "application/octet-stream"
                        : file.ContentType
                });
            }

            return Result<List<ChatFileDto>>.Success(result);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (UploadChatFile): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

