public class BlockChatUserCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<BlockChatUserCommand, Result>
{
    public async Task<Result> Handle(
        BlockChatUserCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            if (currentUserId == request.TargetUserId)
                return ChatErrors.CannotChatWithYourself;

            var targetExists = await context.AppUsers
                .AsNoTracking()
                .AnyAsync(u => u.Id == request.TargetUserId && u.IsActive, cancellationToken);

            if (!targetExists)
                return ChatErrors.ConversationNotFound;

            var alreadyBlocked = await context.ChatBlocks
                .AsNoTracking()
                .AnyAsync(b =>
                    b.BlockerUserId == currentUserId
                    && b.BlockedUserId == request.TargetUserId,
                    cancellationToken);

            if (alreadyBlocked)
                return ChatErrors.AlreadyBlocked;

            context.ChatBlocks.Add(new ChatBlock
            {
                BlockerUserId = currentUserId,
                BlockedUserId = request.TargetUserId,
                BlockedAt = DateTime.UtcNow
            });

            await context.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (BlockChatUser): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

