namespace Application.Features.Command;

public class MessageNotificationCreateCommandHandler(IApplicationDbContext context
    , IDateTimeService dateTime)

    : IRequestHandler<MessageNotificationCreateCommand, Result>
{
    public async Task<Result> Handle(MessageNotificationCreateCommand request, CancellationToken cancellationToken)
    {
        try
        {
            var qMessage = request.model;
            var qCreatorUser = await context.AppUsers
                     .Select(x => new { x.Id, x.Name }).
                     FirstOrDefaultAsync(x => x.Id == qMessage.SenderId);

            NotificationCenter qTaskNoti = null;
            foreach (var reciver in qMessage.Recipients)
            {
                var newNotid = NotificationCenter.Message(qMessage,
                    qCreatorUser!.Name,
                    reciver.AppUserId);

                if (qTaskNoti is null)
                {
                    qTaskNoti = await context.NotificationCenters
                        .Where(x => x.DataId == newNotid.DataId)
                        .Where(x => x.Type == newNotid.Type)
                        .Where(x => x.UserId == newNotid.UserId)
                        .FirstOrDefaultAsync(cancellationToken);
                }
                if (qTaskNoti != null)
                {
                    qTaskNoti.Items.Add(newNotid.Items.First());
                    qTaskNoti.LastDateTime = dateTime.Now;
                }
                else
                {
                    newNotid.LastDateTime = dateTime.Now;
                    context.NotificationCenters.Add(newNotid);
                }
            }
            await context.SaveChangesAsync(cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS: {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}
```

**Pattern:** `NotificationCenter.Message(...)` factory → upsert by `(DataId, Type, UserId)` → append item or `Add` new center → `SaveChangesAsync`.

