    public async Task<Result<ChatMessageDto>> Handle(
        SendChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var participant = await context.ChatParticipants
                .AsNoTracking()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (participant is null)
                return ChatErrors.NotAParticipant;

            var conversationType = await context.ChatConversations
                .AsNoTracking()
                .Where(cv => cv.Id == request.ConversationId)
                .Select(cv => cv.Type)
                .FirstOrDefaultAsync(cancellationToken);

            if (conversationType == ChatConversationType.Channel
                && participant.Role != ChatParticipantRole.Admin)
                return ChatErrors.ChannelMembersCannotSend;

            int? validatedReplyToId = request.ReplyToMessageId;
            if (validatedReplyToId.HasValue)
            {
                var replyExists = await context.ChatMessages
                    .AsNoTracking()
                    .AnyAsync(m =>
                        m.Id == validatedReplyToId.Value
                        && m.ConversationId == request.ConversationId,
                        cancellationToken);

                if (!replyExists)
                    validatedReplyToId = null;
            }

            var message = new ChatMessage
            {
                ConversationId = request.ConversationId,
                SenderId = currentUserId,
                Text = string.IsNullOrWhiteSpace(request.Text) ? null : request.Text.Trim(),
                ReplyToMessageId = validatedReplyToId
            };

            if (request.Attachments.Count > 0)
            {
                var fileResults = await uploadServiceApi.UploadAsync(
                    pathOption.Value.ChatFiles,
                    request.Attachments);

                for (var i = 0; i < request.Attachments.Count; i++)
                {
                    var file = request.Attachments[i];
                    var uploaded = fileResults[i];

                    message.Attachments.Add(new ChatMessageAttachment
                    {
                        FileUrl = uploaded.Name,
                        FileName = file.FileName,
                        FileSize = file.Length,
                        ContentType = string.IsNullOrWhiteSpace(file.ContentType)
                            ? "application/octet-stream"
                            : file.ContentType
                    });
                }
            }

            context.ChatMessages.Add(message);
            await context.SaveChangesAsync(cancellationToken);

            var sender = await context.AppUsers
                .AsNoTracking()
                .Where(u => u.Id == currentUserId)
                .Select(u => new { u.Name, u.ProfileImage })
                .FirstOrDefaultAsync(cancellationToken);

            ChatMessageReplySnapshotDto? replySnapshot = null;
            if (message.ReplyToMessageId.HasValue)
            {
                var original = await context.ChatMessages
                    .AsNoTracking()
                    .Where(m => m.Id == message.ReplyToMessageId.Value)
                    .Select(m => new
                    {
                        m.Id,
                        SenderName = m.Sender.Name,
                        m.Text,
                        m.IsDeleted
                    })
                    .FirstOrDefaultAsync(cancellationToken);

                if (original is not null)
                {
                    replySnapshot = new ChatMessageReplySnapshotDto
                    {
                        MessageId = original.Id,
                        SenderName = original.SenderName,
                        TextPreview = original.IsDeleted ? null : TruncatePreview(original.Text),
                        IsDeleted = original.IsDeleted
                    };
                }
            }

            var dto = new ChatMessageDto
            {
                Id = message.Id,
                ConversationId = message.ConversationId,
                SenderId = currentUserId,
                SenderName = sender?.Name ?? string.Empty,
                SenderAvatarUrl = string.IsNullOrEmpty(sender?.ProfileImage) ? null : sender.ProfileImage,
                Text = message.Text,
                IsDeleted = false,
                IsEdited = false,
                SentAt = message.CreateDate,
                ReplyTo = replySnapshot,
                ForwardedFrom = null,
                Attachments = message.Attachments.Select(a => new ChatFileDto
                {
                    Id = a.Id,
                    FileName = a.FileName,
                    FileUrl = a.FileUrl,
                    FileSize = a.FileSize,
                    ContentType = a.ContentType
                }).ToList()
            };

            await chatNotificationService.SendMessageAsync(
                message.ConversationId,
                dto,
                cancellationToken);

            return Result<ChatMessageDto>.Success(dto);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (SendChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
```

